import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { ResponsiveContainer, AreaChart, Area } from 'recharts';
import { Bitcoin, Coins, CircleDot, Database, Smartphone, XCircle } from 'lucide-react';
import '../../styles/crypto.css';

// Görseldeki her coin için özel ikon ve renk eşleştirmesi
const coinConfigs = {
  'BTCTRY': { name: 'BITCOIN (BTC)', icon: Bitcoin, color: '#F7931A' },
  'ETHTRY': { name: 'ETHEREUM (ETH)', icon: Coins, color: '#627EEA' },
  'SOLTRY': { name: 'SOLANA (SOL)', icon: Smartphone, color: '#14F195' },
  'BNBTRY': { name: 'BINANCE COIN (BNB)', icon: CircleDot, color: '#F3BA2F' },
  'ADATRY': { name: 'CARDANO (ADA)', icon: Database, color: '#0033AD' },
  'XRPTRY': { name: 'XRP (XRP)', icon: XCircle, color: '#FFFFFF' }
};

const CryptoBox = ({ coin }) => {
  const config = coinConfigs[coin.pair] || { name: coin.pair, icon: Coins, color: '#3b82f6' };
  const Icon = config.icon;

  return (
    <div className="crypto-item-box">
      <div className="coin-left-section">
        <div className="coin-icon-wrapper" style={{ backgroundColor: config.color + '22' }}>
          <Icon color={config.color} size={28} />
        </div>
        <div className="coin-details">
          <h3 className="coin-title">{config.name}</h3>
          <p className="coin-price">{parseFloat(coin.last).toLocaleString()} ₺</p>
        </div>
      </div>

      <div className="coin-right-section">
        <div className="sparkline-wrapper">
          <ResponsiveContainer width="100%" height={50}>
            <AreaChart data={coin.chartData}>
              <defs>
                <linearGradient id={`grad-${coin.pair}`} x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor={config.color} stopOpacity={0.3}/>
                  <stop offset="95%" stopColor={config.color} stopOpacity={0}/>
                </linearGradient>
              </defs>
              <Area 
                type="monotone" 
                dataKey="value" 
                stroke={config.color} 
                fill={`url(#grad-${coin.pair})`} 
                strokeWidth={2} 
                dot={false}
              />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default function CryptoMarket() {
  const [data, setData] = useState([]);

  useEffect(() => {
    const fetchMarket = () => {
      axios.get('https://api.btcturk.com/api/v2/ticker')
        .then(res => {
          const filtered = res.data.data.filter(c => coinConfigs[c.pair]).map(c => ({
            ...c,
            chartData: Array.from({ length: 12 }, () => ({ value: Math.random() * 100 }))
          }));
          setData(filtered);
        });
    };

    fetchMarket();
    const timer = setInterval(fetchMarket, 10000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="market-insight-wrapper">
      <h2 className="market-main-title">CRYPTO MARKET INSIGHTS</h2>
      <div className="crypto-boxes-container">
        {data.map(coin => <CryptoBox key={coin.pair} coin={coin} />)}
      </div>
    </div>
  );
}
